class Playground {
    async run(inputs) {
        const inputStr = inputs[0] || '10, 5, 30, 2, 8, 15, 1';
        const vals = inputStr.split(',').map(v => parseInt(v.trim())).filter(n => !isNaN(n));

        this.log('Building Min Heap from input...');
        this.heap.init(vals, 'min');
        this.sorted.init([]);
        await this.await();

        this.log('Pushing value 0...');
        this.heap.push(0);
        await this.await();

        this.log('Pushing value 20...');
        this.heap.push(20);
        await this.await();

        this.log('Starting Heap Sort (Extract Min)...');
        const sortedArr = [];
        while (true) {
            const min = this.heap.pop();
            if (min === null) break;

            this.log(`Extracted Min: ${min}`);
            sortedArr.push(min);
            this.sorted.push(min);
            await this.await();
        }

        this.log('Heap Sort Complete!');
    }
}
